// Normaliza input. Username opcional (default 'admin' para backwards-compat
// con el flujo antiguo que solo pedía password).
const src = $input.first().json;
const body = src.body || src;
const username = ((body.username || 'admin') + '').trim().toLowerCase();
const password = (body.password || '') + '';
const ip = (src.headers && (src.headers['x-forwarded-for'] || src.headers['x-real-ip'])) || '';
const ua = (src.headers && src.headers['user-agent']) || '';
if (!password || password.length > 200) {
  return [{ json: { _abort: true, ok: false, reason: 'invalid_password', username, ip, ua } }];
}
return [{ json: { username, password, ip, ua } }];

// Verifica password con bcrypt. Lockout suave después de 5 intentos
// fallidos consecutivos en la última hora.
//
// Requiere que el contenedor n8n tenga `bcryptjs` y `jsonwebtoken` disponibles
// como módulos externos. En n8n self-hosted: NODE_FUNCTION_ALLOW_EXTERNAL=*
// (o lista explícita ['bcryptjs','jsonwebtoken']).
//
// JWT_SECRET vive en la env del contenedor n8n (NUNCA en el repo). Generar
// con `openssl rand -base64 48` y meter en Railway env vars.
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const norm = $('Normalize input').first().json;
const row = $input.first().json || {};
const now = Date.now();

if (!row.id) {
  return [{ json: { ok: false, reason: 'invalid_credentials', message: 'Usuario o contraseña incorrectos.', _audit: { action: 'login.fail.no_user', success: false, username: norm.username, ip: norm.ip, ua: norm.ua } } }];
}
if (row.locked_until && new Date(row.locked_until).getTime() > now) {
  return [{ json: { ok: false, reason: 'locked', message: 'Cuenta bloqueada temporalmente. Intenta más tarde.', _audit: { action: 'login.fail.locked', success: false, username: norm.username, ip: norm.ip, ua: norm.ua } } }];
}

let ok = false;
try { ok = bcrypt.compareSync(norm.password, row.password_hash); }
catch { ok = false; }

if (!ok) {
  return [{ json: { ok: false, reason: 'invalid_credentials', message: 'Usuario o contraseña incorrectos.', _audit: { action: 'login.fail.bad_password', success: false, username: norm.username, ip: norm.ip, ua: norm.ua, failed_attempts: (row.failed_attempts || 0) + 1 } } }];
}

const secret = $env.JWT_SECRET;
if (!secret || secret.length < 32) {
  return [{ json: { ok: false, reason: 'misconfigured', message: 'Servidor mal configurado: JWT_SECRET ausente o débil. Contacta soporte.', _audit: { action: 'login.fail.no_secret', success: false, username: norm.username, ip: norm.ip, ua: norm.ua } } }];
}

const ttlSeconds = 8 * 60 * 60; // 8h
const token = jwt.sign({ sub: row.id, username: row.username, role: row.role || 'admin' }, secret, { expiresIn: ttlSeconds, issuer: 'solarhub', audience: 'admin' });
const expiresAt = now + ttlSeconds * 1000;

return [{ json: { ok: true, token, expiresAt, role: row.role || 'admin', _audit: { action: 'login.success', success: true, username: norm.username, ip: norm.ip, ua: norm.ua, user_id: row.id } } }];

// Limpia campos internos (_audit) antes de responder al cliente.
const { _audit, ...rest } = $input.first().json;
return [{ json: rest }];
